+  private getCursorPagination(opts: CrudOptions) {
+    if (opts.cursor && !opts.orderBy) {
+      throw new BadRequestException('cursor requires orderBy');
+    }
+    if (opts.cursor && opts.offset !== undefined) {
+      throw new BadRequestException('cursor cannot be used with offset');
+    }
+    if (!opts.orderBy || !opts.limit) {
+      return null;
+    }
+
+    const sort = this.normalizeCursorSort(opts.orderBy);
+    const idField = this.crudConfig.id_field as string;
+    if (!sort.some(([field]) => field === idField)) {
+      sort.push([idField, 'asc']);
+    }
+
+    const orderBy = sort.map(([field, direction]) => ({ [field]: direction }));
+    if (!opts.cursor) {
+      return { orderBy, sort, query: null };
+    }
+
+    const payload = this.decodeCursor(opts.cursor);
+    const expectedSort = sort.map(([field, direction]) => `${field}:${direction}`).join(',');
+    if (payload.__sort !== expectedSort) {
+      throw new BadRequestException('cursor sort does not match orderBy');
+    }
+    for (const [field] of sort) {
+      if (!Object.prototype.hasOwnProperty.call(payload, field)) {
+        throw new BadRequestException(`cursor is missing ${field}`);
+      }
+    }
+    if (!Object.prototype.hasOwnProperty.call(payload, idField)) {
+      throw new BadRequestException(`cursor is missing ${idField}`);
+    }
+
+    return {
+      orderBy,
+      sort,
+      query: {
+        $or: sort.map(([field, direction], index) => ({
+          ...Object.fromEntries(
+            sort.slice(0, index).map(([previousField]) => [
+              previousField,
+              payload[previousField],
+            ]),
+          ),
+          [field]: { [direction === 'asc' ? '$gt' : '$lt']: payload[field] },
+        })),
+      },
+    };
+  }
+
+  private normalizeCursorSort(orderBy: CrudOptions['orderBy']): [string, 'asc' | 'desc'][] {
+    const entries = (Array.isArray(orderBy) ? orderBy : [orderBy]).flatMap(
+      (part) => Object.entries(part || {}),
+    );
+    if (!entries.length) {
+      throw new BadRequestException('cursor requires orderBy');
+    }
+    return entries.map(([field, value]) => {
+      const direction =
+        value === 1 || String(value).toLowerCase() === 'asc'
+          ? 'asc'
+          : value === -1 || String(value).toLowerCase() === 'desc'
+            ? 'desc'
+            : null;
+      if (!direction) {
+        throw new BadRequestException('cursor only supports asc or desc orderBy');
+      }
+      return [field, direction];
+    });
